# FUNCTIONS/RULES FOR OPERATIONS

class ModAdd:
    """Family of modular arithmetic binary operations, described by addition mod n."""

    def __init__(self, n: int):
        self.n = n

    def __call__(self, a: int, b: int):
        return (a + b) % self.n

def add(a: int, b: int) -> int:
    return a + b

# MISCELLANEOUS

def cartesian_product(A: Set[Any], B: Set[Any]) -> Set[tuple[Any, Any]]:
    # Useless for now but still successfully makes a Cartesian product so keeping it

    AxB = set()

    for element1 in A:
        for element2 in B:
            AxB.add((element1, element2))

    return AxB

